import os
from google.cloud import storage

def get_latest_model():
    bucket_name = 'your-bucket-name'
    model_path = os.environ.get('MODEL_PATH')
    
    client = storage.Client()
    bucket = client.bucket(bucket_name)
    blobs = list(bucket.list_blobs(prefix=model_path))
    
    if len(blobs) == 0:
        raise Exception(f"No models found in {model_path}")
        
    latest_blob = max(blobs, key=lambda x: x.updated)
    return f"gs://{bucket_name}/{latest_blob.name}"

def load_model(model_path):
    import tensorflow as tf
    
    gcs_path = model_path
    model = tf.saved_model.load(gcs_path)
    
    # Get the default signature
    input_details = model.signatures['serving_default'].inputs
    output_details = model.signatures['serving_default'].outputs
    
    return model

def main():
    model_path = get_latest_model()
    print(f"Loaded model from: {model_path}")
    model = load_model(model_path)
    
if __name__ == "__main__":
    main()